// Generated from the archived WordPress portfolio markup.
export const portfolioHtml = "<h2 class=\"wp-block-heading\" id=\"mattel\">MATTEL Inc - Art Director of Digital Gaming</h2>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Hotwheels-Party-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"539\" data-id=\"564\" src=\"/assets/images/2025/04/Hotwheels-Party-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Hotwheels Party\" class=\"wp-image-564\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Hotwheels-Gravity-Select-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"539\" data-id=\"562\" src=\"/assets/images/2025/04/Hotwheels-Gravity-Select-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Hotwheels Gravity Select\" class=\"wp-image-562\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Hotwheels-Gravity-Race-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"539\" data-id=\"561\" src=\"/assets/images/2025/04/Hotwheels-Gravity-Race-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Hotwheels Gravity Race\" class=\"wp-image-561\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">At Mattel, I’ve been focused on helping shape the company’s growing digital gaming efforts from the ground up. I work closely with internal studios to guide early concept development, project roadmapping, and art team reviews, ensuring creative quality across multiple initiatives. My role also involves identifying opportunities to expand Mattel IP in interactive spaces and exploring new workflows, including the integration of AI-assisted design tools. A big part of my work here has been building strategies for scalability while staying hands-on during concept and prototyping phases.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-2 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Barbie-Royal_01-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"539\" height=\"1024\" data-id=\"560\" src=\"/assets/images/2025/04/Barbie-Royal_01-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Barbie Royal 01\" class=\"wp-image-560\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Barbie-Royal-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"539\" height=\"1024\" data-id=\"559\" src=\"/assets/images/2025/04/Barbie-Royal-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Barbie Royal\" class=\"wp-image-559\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/04/Barbie-Fashion_04-scaled.png\"><img loading=\"lazy\" decoding=\"async\" width=\"539\" height=\"1024\" data-id=\"555\" src=\"/assets/images/2025/04/Barbie-Fashion_04-scaled.png\" alt=\"MATTEL Inc - Art Director of Digital Gaming: Barbie Fashion 04\" class=\"wp-image-555\"></a></figure>\n</figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"tales\">Tales - Art Director and CO-Founder</h2>\n\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"https://talescreator.com/\" rel=\"noopener noreferrer\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"1746\" height=\"384\" src=\"/assets/images/2023/07/Screenshot-2023-07-17-161647.png\" alt=\"Tales - Art Director and CO-Founder: Screenshot 2023 07 17 161647\" class=\"wp-image-367\"></a></figure>\n</div>\n\n\n<h3 class=\"wp-block-heading\"><strong>Welcome to My Creative Journey at <a href=\"https://talescreator.com/\" rel=\"noopener noreferrer\" target=\"_blank\">Tales</a></strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">In my latest endeavor as the Art Director for Tales, a groundbreaking platform redefining interactive storytelling, we’ve woven an intricate tapestry of art, technology, and innovative narrative techniques. Tales empowers writers to seamlessly transition into game designers, crafting immersive “choose your own adventure” tales that captivate and engage.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-3 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/03/Story-Editor-Copy.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"613\" data-id=\"535\" src=\"/assets/images/2025/03/Story-Editor-Copy.png\" alt=\"Welcome to My Creative Journey at Tales: Story Editor\" class=\"wp-image-535\"></a><figcaption class=\"wp-element-caption\">Story Editor</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/03/Character-Creation-Tool-Copy.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"613\" data-id=\"537\" src=\"/assets/images/2025/03/Character-Creation-Tool-Copy.png\" alt=\"Welcome to My Creative Journey at Tales: Character Creation Tool\" class=\"wp-image-537\"></a><figcaption class=\"wp-element-caption\">Avatar Creator</figcaption></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">What truly sets my tenure at Tales apart is a blend of global collaboration and next-gen technology. Commanding a decentralized art team spread across multiple continents and time zones, I’ve fostered an ethos of creativity, respect, and professionalism. Each artist, irrespective of location, is an integral cog in our creative machinery, contributing to a diverse and rich tapestry of storytelling.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-4 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/ScareStreet_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1884\" height=\"2560\" data-id=\"507\" src=\"/assets/images/2025/02/ScareStreet_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: ScareStreet cover\" class=\"wp-image-507\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/PosterGirl_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"504\" src=\"/assets/images/2025/02/PosterGirl_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: PosterGirl cover\" class=\"wp-image-504\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/ApexPredators_cover_tall-1.jpg\"><img decoding=\"async\" data-id=\"442\" src=\"/assets/images/2025/02/ApexPredators_cover_tall-1.jpg\" alt=\"Welcome to My Creative Journey at Tales: ApexPredators cover 1\" class=\"wp-image-442\" loading=\"lazy\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">With the innovations in AI, Tales underwent a transformative evolution. The integration of AI into our Tales Creator was a monumental achievement, expediting the story publishing process from months to days and quadrupling our asset library. This utilization of AI revolutionized the creation of environments, actors, and covers, bringing efficiency and scale to our platform.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-5 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/VampireGames_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"472\" src=\"/assets/images/2025/02/VampireGames_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: VampireGames cover\" class=\"wp-image-472\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/SorcerySpellcraft_cover-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"467\" src=\"/assets/images/2025/02/SorcerySpellcraft_cover-scaled.jpg\" alt=\"Welcome to My Creative Journey at Tales: SorcerySpellcraft cover\" class=\"wp-image-467\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/NerdDetective_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"463\" src=\"/assets/images/2025/02/NerdDetective_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: NerdDetective cover\" class=\"wp-image-463\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/MascaraMurders_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"462\" src=\"/assets/images/2025/02/MascaraMurders_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: MascaraMurders cover\" class=\"wp-image-462\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/LightsInTheMist_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"451\" src=\"/assets/images/2025/02/LightsInTheMist_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: LightsInTheMist cover\" class=\"wp-image-451\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/EverythingYouEverWanted_cover_tall.jpg\"><img decoding=\"async\" data-id=\"444\" src=\"/assets/images/2025/02/EverythingYouEverWanted_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: EverythingYouEverWanted cover\" class=\"wp-image-444\" loading=\"lazy\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">Additionally, I was instrumental in designing and building parts of the Avatar system, creating an intuitive UI &amp; UX for both the app and the Tales Creator tool. This work not only enhanced the functionality of our platform but also made it more accessible to our burgeoning community of storytellers.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-6 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/03/readers-storytelliing-remixed.png\"><img loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"700\" data-id=\"550\" src=\"/assets/images/2025/03/readers-storytelliing-remixed.png\" alt=\"Welcome to My Creative Journey at Tales: readers storytelliing remixed\" class=\"wp-image-550\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/03/Story-Book-2.png\"><img loading=\"lazy\" decoding=\"async\" width=\"375\" height=\"768\" data-id=\"545\" src=\"/assets/images/2025/03/Story-Book-2.png\" alt=\"Welcome to My Creative Journey at Tales: Story Book 2\" class=\"wp-image-545\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/03/IMG_1633-Copy.png\"><img loading=\"lazy\" decoding=\"async\" width=\"473\" height=\"1024\" data-id=\"538\" src=\"/assets/images/2025/03/IMG_1633-Copy.png\" alt=\"Welcome to My Creative Journey at Tales: IMG 1633\" class=\"wp-image-538\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-7 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/VampireFiction_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"471\" src=\"/assets/images/2025/02/VampireFiction_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: VampireFiction cover\" class=\"wp-image-471\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/GoldenThread_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"447\" src=\"/assets/images/2025/02/GoldenThread_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: GoldenThread cover\" class=\"wp-image-447\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/DemoniqueAndTheHellHunter_cover_tall-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"454\" src=\"/assets/images/2025/02/DemoniqueAndTheHellHunter_cover_tall-scaled.jpg\" alt=\"Welcome to My Creative Journey at Tales: DemoniqueAndTheHellHunter cover\" class=\"wp-image-454\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">Moreover, I expanded our team and network of artists globally, directing a diverse group of talents generating art for both in-game experiences and our extensive asset library. This expansion was a testament to our commitment to inclusivity and artistic excellence, empowering a broad spectrum of voices and visions.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-8 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/SaveTheQueen_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"520\" src=\"/assets/images/2025/02/SaveTheQueen_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: SaveTheQueen cover\" class=\"wp-image-520\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/Walk_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"518\" src=\"/assets/images/2025/02/Walk_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: Walk cover\" class=\"wp-image-518\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/SurviveTheStorm_cover-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"514\" src=\"/assets/images/2025/02/SurviveTheStorm_cover-1.jpg\" alt=\"Welcome to My Creative Journey at Tales: SurviveTheStorm cover 1\" class=\"wp-image-514\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">What’s awe-inspiring is that our small, yet dynamic team outperformed and produced at a scale reminiscent of a massive studio. More than just delivering art, we achieved unmatched efficiency, creating superior value with limited resources. Our journey was not without its challenges, but dreaming big and balancing resource constraints led us to innovative solutions that have redefined what a small team can accomplish.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-9 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/SomebodyMurderedSnakeyDrake_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"513\" src=\"/assets/images/2025/02/SomebodyMurderedSnakeyDrake_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: SomebodyMurderedSnakeyDrake cover\" class=\"wp-image-513\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/MirrorMirror_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"497\" src=\"/assets/images/2025/02/MirrorMirror_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: MirrorMirror cover\" class=\"wp-image-497\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/MidnightSpirits_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"495\" src=\"/assets/images/2025/02/MidnightSpirits_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: MidnightSpirits cover\" class=\"wp-image-495\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">At the heart of Tales lies an unwavering belief: to empower every indie writer and artist. We are creating an ecosystem where any storyteller, regardless of their scale, can craft masterpieces with the tools and prowess of big studios. Our goal is not just to publish but to enable storytellers to thrive economically, breaking barriers and standing tall, independent, and successful.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-10 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/ShadowsOfGlastonburyManor_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"510\" src=\"/assets/images/2025/02/ShadowsOfGlastonburyManor_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: ShadowsOfGlastonburyManor cover\" class=\"wp-image-510\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/MurderInSleepyOaks_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"499\" src=\"/assets/images/2025/02/MurderInSleepyOaks_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: MurderInSleepyOaks cover\" class=\"wp-image-499\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/NightMatch_cover-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"500\" src=\"/assets/images/2025/02/NightMatch_cover-1.jpg\" alt=\"Welcome to My Creative Journey at Tales: NightMatch cover 1\" class=\"wp-image-500\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/Ouija_cover-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"501\" src=\"/assets/images/2025/02/Ouija_cover-1.jpg\" alt=\"Welcome to My Creative Journey at Tales: Ouija cover 1\" class=\"wp-image-501\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/HeirtotheThrone_cover.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"754\" height=\"1024\" data-id=\"491\" src=\"/assets/images/2025/02/HeirtotheThrone_cover.jpg\" alt=\"Welcome to My Creative Journey at Tales: HeirtotheThrone cover\" class=\"wp-image-491\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/FreedomTrigger_cover_tall.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"753\" height=\"1024\" data-id=\"489\" src=\"/assets/images/2025/02/FreedomTrigger_cover_tall.jpg\" alt=\"Welcome to My Creative Journey at Tales: FreedomTrigger cover\" class=\"wp-image-489\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-11 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/SeriousWeirdness_cover_wide-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"573\" data-id=\"509\" src=\"/assets/images/2025/02/SeriousWeirdness_cover_wide-1.jpg\" alt=\"Welcome to My Creative Journey at Tales: SeriousWeirdness cover 1\" class=\"wp-image-509\"></a></figure>\n</figure>\n\n\n\n<p class=\"wp-block-paragraph\">Join me on this voyage at Tales, exploring the fusion of creativity and technology, where each story is a beacon of empowerment, and every art decision is a step towards a more inclusive and vibrant creative world.</p>\n\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"https://talescreator.com/\" rel=\"noopener noreferrer\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"1746\" height=\"384\" src=\"/assets/images/2023/07/Screenshot-2023-07-17-161647.png\" alt=\"Welcome to My Creative Journey at Tales: Screenshot 2023 07 17 161647\" class=\"wp-image-367\"></a></figure>\n</div>\n\n\n<h1 class=\"wp-block-heading\" id=\"past-projects\"><strong>Past Projects:</strong></h1>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"ea-visceral\"><strong>EA Games/Visceral - Lead Artist</strong></h2>\n\n\n\n<figure class=\"wp-block-image\"><img decoding=\"async\" src=\"/assets/images/external/oyster.ignimgs.com/mediawiki/apis.ign.com/battlefield-5/0/07/Hardline.jpg\" alt=\"Battlefield Hardline Guide - IGN\" loading=\"lazy\"></figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">At EA Games, working on the prestigious Battlefield project, my role as a Lead Artist involved orchestrating a complex and efficient outsourcing operation. I was at the forefront of managing the art asset outsourcing from EA Shanghai, a role that demanded not only artistic insight but also strategic collaboration and communication skills. My interactions with EA Shanghai’s art directors, leads, and project managers were pivotal in establishing crystal-clear expectations and ensuring a seamless workflow.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-12 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/2555467-battlefield-hardline-4-wm-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" data-id=\"527\" src=\"/assets/images/2025/02/2555467-battlefield-hardline-4-wm-1.jpg\" alt=\"EA Games/Visceral - Lead Artist: 2555467 battlefield hardline 4 wm 1\" class=\"wp-image-527\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/battlefield-hardline-2000-c37b3ccd10754140ac9addd0f42a958b.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" data-id=\"526\" src=\"/assets/images/2025/02/battlefield-hardline-2000-c37b3ccd10754140ac9addd0f42a958b.jpg\" alt=\"EA Games/Visceral - Lead Artist: battlefield hardline 2000 c37b3ccd10754140ac9addd0f42a958b\" class=\"wp-image-526\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">My responsibilities extended beyond external coordination. Internally, I liaised with team leads, designers, producers, and development directors at EA Games to thoroughly assess our outsourcing needs. I was instrumental in curating comprehensive asset lists, delineating aesthetic benchmarks for each request, and ensuring these aligned perfectly with the Battlefield project’s vision.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A critical aspect of my role was defining precise technical specifications for all outsourced assets. This process involved meticulous scrutiny to guarantee that each asset not only met our aesthetic standards but also adhered strictly to the technical requirements of the Battlefield engine and gameplay mechanics. My approach was detail-oriented and rigorous, ensuring no compromise on quality or performance.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-13 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/c9a65c69-20f6-4b12-a41e-ae957ac6db1b.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" data-id=\"524\" src=\"/assets/images/2025/02/c9a65c69-20f6-4b12-a41e-ae957ac6db1b.jpg\" alt=\"EA Games/Visceral - Lead Artist: c9a65c69 20f6 4b12 a41e ae957ac6db1b\" class=\"wp-image-524\"></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"/assets/images/2025/02/IcYUMbN.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" data-id=\"525\" src=\"/assets/images/2025/02/IcYUMbN.jpg\" alt=\"EA Games/Visceral - Lead Artist: IcYUMbN\" class=\"wp-image-525\"></a></figure>\n</figure>\n\n\n\n\n\n\n\n<p class=\"wp-block-paragraph\">As the Asset Manager, my oversight encompassed both in-house and outsourced assets. I developing an efficient asset outsourcing pipeline and review process, streamlining the integration of these assets into our production workflow. This role was not just about managing assets; it was about fostering a synergy between in-house creativity and outsourced efficiency, ensuring the artistic and technical integrity of the Battlefield project at every stage.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In this multifaceted role at EA Games, I was committed to bridging the gap between creative aspirations and practical execution, ensuring the Battlefield project not only met but exceeded the high standards synonymous with EA’s legacy in gaming.</p>\n\n\n\n\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Battlefield Hardline: Official Launch Gameplay Trailer\" width=\"760\" height=\"428\" src=\"https://www.youtube.com/embed/yWVPoUCxAC4?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\"></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"bigpoint\"><strong>BigPoint - Lead Artist and Art Director</strong></h2>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"https://www.youtube.com/watch?v=VqWeMw0PqIY\" rel=\"noopener noreferrer\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"200\" src=\"/assets/images/2015/08/umo.jpg\" alt=\"BigPoint - Lead Artist and Art Director: umo\" class=\"wp-image-269\"></a></figure>\n\n\n\n\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Universal Monsters Online Beta Gameplay Commentary - First Look HD\" width=\"760\" height=\"428\" src=\"https://www.youtube.com/embed/EXmU3pSyGvY?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">As the Lead Artist helming Universal Monsters Online (UMO), I orchestrated the efforts of a dynamic team of over 12 skilled artists, each specializing in various domains such as concept art, character design, environmental art, animation, VFX, UI, tech, and web design. UMO, an imaginative and free-to-play browser-based MOBA, ingeniously revived the iconic characters from Universal’s classic horror films.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Influenced by the acclaimed gameplay of League of Legends, UMO emerged as a distinctively enthralling experience, captivating players with its innovative capture-the-flag mechanic and meticulously crafted progression system. My role was pivotal in shaping the game’s artistic direction, channeling the essence of each legendary monster into the digital realm. It was a journey of creative exploration and technical mastery, culminating in a gaming world that not only paid homage to these timeless characters but also pushed the boundaries of artistic excellence in browser-based gaming.</p>\n\n\n\n<p class=\"wp-block-paragraph\">My leadership in this project was not just about managing a team; it was about mentoring, fostering a shared vision, translating classic horror into a modern gameplay experience, and setting a new standard in artistry and engagement in a browser game.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/GDC_poster.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"2440\" height=\"1373\" src=\"/assets/images/2013/01/GDC_poster.jpg\" alt=\"GDC_poster\" class=\"wp-image-71\"></a><figcaption class=\"wp-element-caption\">Poster by Christian MacNevin</figcaption></figure>\n</div>\n\n\n<p class=\"wp-block-paragraph\"><strong>Direction:</strong><br>Crafting an art bible stands as a cornerstone in the journey of visual storytelling, serving as the vital blueprint that shapes and solidifies a game’s aesthetic core. This comprehensive guide is more than just a reference document; it is the artistic compass that unites and aligns the entire creative team. It encapsulates the essence of our vision, detailing every nuance of the game’s art style, from the sweeping grandeur of landscapes to the intricate details of character designs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In my role, I ensured that our art bible was both exhaustive and inspiring, a living document that evolved with our project. It was instrumental in providing clarity and direction, not only to our seasoned artists but also in guiding new members as they seamlessly integrated into our creative endeavor. By meticulously constructing this art bible, we established a unified and coherent visual language that resonated throughout every aspect of the game, ensuring a harmonious and immersive player experience.</p>\n\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/art_bible_samples_02.jpg\"><img decoding=\"async\" src=\"/assets/images/2013/01/art_bible_samples_02.jpg\" alt=\"art_bible_samples_01\" class=\"wp-image-65\" loading=\"lazy\"></a><figcaption class=\"wp-element-caption\">3D Character Models by Eric Maki Concepts by Christian MacNevin</figcaption></figure>\n</div>\n\n\n<p class=\"wp-block-paragraph\"><strong>Character Pipeline:</strong><br>The development of our monster characters began with a crucial first step: an initial sketch, conceptualized under my guidance. This initial sketch served as the foundational vision for each character, capturing the essence of what they would become. Once this vision was crystallized, I entrusted it to our talented concept artist, initiating a streamlined and efficient pipeline.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This approach was instrumental in setting clear and precise expectations right from the outset, ensuring that every stage of the character’s development was aligned with the original artistic vision. It was a process marked by clarity and efficiency, where each sketch became the catalyst for the character’s journey from concept to digital reality. This method not only optimized our workflow but also ensured that the heart and soul of each monster were preserved and accentuated throughout their development, resulting in characters that were both true to their origins and captivating to our audience.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/monsters_character_pipeline.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"3280\" height=\"1846\" src=\"/assets/images/2015/08/monsters_character_pipeline.jpg\" alt=\"monsters_character_pipeline\" class=\"wp-image-281\"></a></figure>\n</div>\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/s_02.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1920\" height=\"1080\" src=\"/assets/images/2013/01/s_02.jpg\" alt=\"BigPoint - Lead Artist and Art Director: s 02\" class=\"wp-image-62\"></a><figcaption class=\"wp-element-caption\">In-Game screenshots</figcaption></figure>\n</div>\n\n\n<p class=\"wp-block-paragraph\"><strong>Environments:</strong><br>As the driving force behind our game’s level design and world-building, I took the helm in crafting intricate, immersive environments that formed the backbone of our gaming experience. My approach combined a keen eye for spatial aesthetics with a deep understanding of narrative-driven design, ensuring that each level was not only visually stunning but also seamlessly integrated with the game’s story and mechanics.</p>\n\n\n\n<p class=\"wp-block-paragraph\">My responsibility extended to meticulously orchestrating the lighting and visual effects, elements crucial in bringing each scene to life. I employed lighting not just as an illumination tool but as a storytelling device, using it to set moods, highlight key elements, and guide player focus. The addition of carefully curated visual effects further enriched the environments, adding layers of realism and dynamism.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This holistic approach to level design and world-building - encompassing layout, lighting, and VFX - was instrumental in creating captivating worlds that engaged players. It was a process that melded artistry with technical prowess, resulting in spaces that were not only functional and navigable but also rich in atmosphere and depth.</p>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/s_01.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1920\" height=\"1080\" src=\"/assets/images/2013/01/s_01.jpg\" alt=\"s_01\" class=\"wp-image-61\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/s_04.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1920\" height=\"1080\" src=\"/assets/images/2013/01/s_04.jpg\" alt=\"s_04\" class=\"wp-image-60\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/s_03.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1920\" height=\"1080\" src=\"/assets/images/2013/01/s_03.jpg\" alt=\"s_03\" class=\"wp-image-59\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/bavaria_03.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1539\" height=\"921\" src=\"/assets/images/2013/01/bavaria_03.jpg\" alt=\"bavaria_03\" class=\"wp-image-70\"></a></figure>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/bavaria_02.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1539\" height=\"921\" src=\"/assets/images/2013/01/bavaria_02.jpg\" alt=\"bavaria_02\" class=\"wp-image-69\"></a><figcaption class=\"wp-element-caption\"><a style=\"display: inline !important;\" href=\"/assets/images/2013/01/bavaria_01.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1539\" height=\"921\" class=\"wp-image-68 size-full\" src=\"/assets/images/2013/01/bavaria_01.jpg\" alt=\"bavaria_01\"></a></figcaption></figure>\n</div>\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/bavaria_04.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1539\" height=\"921\" src=\"/assets/images/2013/01/bavaria_04.jpg\" alt=\"bavaria_04\" class=\"wp-image-67\"></a></figure>\n\n\n\n\n\n\n\n<figure class=\"wp-block-image\"><a href=\"http://www.youtube.com/watch?v=CmKYeDfhA_s\" rel=\"noopener noreferrer\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"200\" src=\"/assets/images/2013/01/ruined_011.jpg\" alt=\"BigPoint - Lead Artist and Art Director: ruined 011\" class=\"wp-image-277\"></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">As the Lead Artist for ‘Ruined Online,’ I had the privilege of leading a talented team of artists, each specialized in their own domain - environment, character, VFX, and UI artistry. My role was multifaceted, involving not only the leadership and coordination of this diverse team but also direct involvement in a variety of artistic disciplines.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Official Ruined Online Trailer 2011 - Bigpoint\" width=\"760\" height=\"428\" src=\"https://www.youtube.com/embed/CmKYeDfhA_s?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">In addition to guiding the overall artistic direction, I actively contributed to the hands-on creation of the game’s elements. This included designing intricate environments, developing unique character concepts, crafting visually stunning VFX, and shaping the game’s UI design. My involvement spanned the full spectrum of the game’s artistic development, ensuring a cohesive and compelling visual experience.</p>\n\n\n\n<div class=\"wp-block-group is-nowrap is-layout-flex wp-container-core-group-is-layout-8f761849 wp-block-group-is-layout-flex\"><div class=\"wp-block-image\">\n<figure class=\"aligncenter is-resized\"><img loading=\"lazy\" decoding=\"async\" width=\"665\" height=\"1024\" src=\"/assets/images/2013/01/5059622670_67757f02cb_b.jpg\" alt=\"5059622670_67757f02cb_b\" class=\"wp-image-26\" style=\"width:370px;height:auto\"></figure>\n</div>\n\n\n<figure class=\"wp-block-image size-full is-resized\"><a href=\"/assets/images/2013/01/5059626000_60d50006c2_b.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"791\" height=\"1024\" src=\"/assets/images/2013/01/5059626000_60d50006c2_b.jpg\" alt=\"BigPoint - Lead Artist and Art Director: 5059626000 60d50006c2 b\" class=\"wp-image-27\" style=\"width:437px;height:auto\"></a></figure>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">‘Ruined Online’ presented itself as a 3rd person shooter battle arena game, set in the post-apocalyptic ruins of famous U.S. cities and landmarks. This PvP, F2P game, built using the Unity3D engine, was a blend of fast-paced gameplay and striking comic book-style art direction. Players engaged in intense battles across iconic locations like the Golden Gate Bridge, Alcatraz, and Fort Mason, with plans to expand to Liberty Island and NY Central Park Zoo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Collaboration was key in the development of ‘Ruined Online.’ Working closely with the tech team, I was involved in addressing and overcoming significant technical challenges, such as managing fluctuating draw calls vital for maintaining game performance, especially crucial for a browser-based game designed for minimum spec machines. Another critical task was minimizing the game’s download size, an essential aspect of providing quick access, a core expectation of browser gaming.</p>\n\n\n\n<p class=\"wp-block-paragraph\">My partnership with the marketing team was equally integral. Together, we strategized on how best to showcase the game’s unique features and artistic qualities, ensuring that our marketing efforts resonated with our target audience and accurately represented the game’s immersive world.</p>\n\n\n\n<p class=\"wp-block-paragraph\">My role in ‘Ruined Online’ went beyond traditional art direction. It was a blend of creative leadership, hands-on artistic contribution, technical problem-solving, and strategic marketing collaboration. This comprehensive approach not only shaped the game into an engaging experience but also highlighted my dedication to overcoming the unique challenges of browser-based gaming.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/GG_screen_01.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1896\" height=\"1020\" src=\"/assets/images/2013/01/GG_screen_01.jpg\" alt=\"GG_screen_01\" class=\"wp-image-49\"></a></figure>\n</div>\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/GG_screen_02.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1896\" height=\"1020\" src=\"/assets/images/2013/01/GG_screen_02.jpg\" alt=\"GG_screen_02\" class=\"wp-image-48\"></a></figure>\n</div>\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/RuiNED_GGB.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1899\" height=\"1141\" src=\"/assets/images/2013/01/RuiNED_GGB.jpg\" alt=\"RuiNED_GGB\" class=\"wp-image-31\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/5059622920_014458a322_b.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"549\" src=\"/assets/images/2013/01/5059622920_014458a322_b.jpg\" alt=\"5059622920_014458a322_b\" class=\"wp-image-29\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2013/01/ruined_Alcatraz.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1899\" height=\"1141\" src=\"/assets/images/2013/01/ruined_Alcatraz.jpg\" alt=\"ruined_Alcatraz\" class=\"wp-image-30\"></a></figure>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/attachment1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1896\" height=\"1020\" src=\"/assets/images/2013/01/attachment1.jpg\" alt=\"attachment\" class=\"wp-image-46\"></a></figure>\n</div>\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/Ruined-Online_2D_Screen1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1338\" height=\"720\" src=\"/assets/images/2013/01/Ruined-Online_2D_Screen1.jpg\" alt=\"Ruined-Online_2D_Screen1\" class=\"wp-image-47\"></a></figure>\n</div>\n\n\n<div class=\"wp-block-group is-nowrap is-layout-flex wp-container-core-group-is-layout-8f761849 wp-block-group-is-layout-flex\">\n<figure class=\"wp-block-image is-resized\"><a href=\"/assets/images/2013/01/ruined_weapons1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"733\" height=\"1024\" src=\"/assets/images/2013/01/ruined_weapons1.jpg\" alt=\"ruined_weapons\" class=\"wp-image-38\" style=\"width:430px;height:auto\"></a></figure>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"/assets/images/2015/08/liberty_island.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"1350\" src=\"/assets/images/2015/08/liberty_island.jpg\" alt=\"liberty_island\" class=\"wp-image-303\"></a></figure>\n</div>\n\n\n\n\n\n\n\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"visual-concepts\">Visual Concepts/2K Sports - Senior 3D Artist</h2>\n\n\n\n<figure class=\"wp-block-image\"><a href=\"https://www.youtube.com/watch?v=vCYMSLbMqOQ\" rel=\"noopener noreferrer\" target=\"_blank\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"200\" src=\"/assets/images/2015/08/2k.jpg\" alt=\"Visual Concepts/2K Sports - Senior 3D Artist: 2k\" class=\"wp-image-267\"></a></figure>\n\n\n\n\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Major League Baseball 2K10 Xbox 360 Trailer - Sizzle Trailer\" width=\"760\" height=\"428\" src=\"https://www.youtube.com/embed/XCZHhW3rjts?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">At 2K Sports, my journey encompassed a diverse spectrum of responsibilities, each underpinning the realism and authenticity of professional sports titles like MLB, NBA, and NHL. A significant part of my role as a Senior Environment Artist and Lead Environment Artist involved creating technically accurate digital representations of arenas and stadiums. This task was not just about visual fidelity but also about meeting the high expectations of fans and players who sought a simulation sports game that mirrored real life. My commitment to authenticity was reflected in every digital rendition of the sports settings, ensuring they resonated with the realism and detail that fans expected.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/4_Boston_Facade2.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"936\" height=\"527\" src=\"/assets/images/2015/08/4_Boston_Facade2.jpg\" alt=\"4_Boston_Facade2\" class=\"wp-image-295\"></a><figcaption class=\"wp-element-caption\">Fenway Park facade - Home of the Boston Redsox</figcaption></figure>\n</div>\n\n\n<p class=\"wp-block-paragraph\">In my role as a Lighter, I focused on using lighting to not only enhance the visual appeal but also to add to the game’s realism and intensity. I crafted lighting scenarios that mirrored real-world sports events, contributing significantly to the immersive experience of the games.</p>\n\n\n\n<p class=\"wp-block-paragraph\">As the leader of the cut-scenes group, I worked to capture the drama and emotional highs of sports, translating key moments into engaging cinematic sequences. This role required a blend of technical skill and narrative flair, enabling me to bring the excitement of professional sports into the digital realm in a way that was both dynamic and emotionally engaging.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/3_NY_Yankees_Facade1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"864\" height=\"515\" src=\"/assets/images/2015/08/3_NY_Yankees_Facade1.jpg\" alt=\"3_NY_Yankees_Facade1\" class=\"wp-image-294\"></a><figcaption class=\"wp-element-caption\">Yankee Stadium “The House that Ruth Built” - Old home of the New York Yankees</figcaption></figure>\n</div>\n\n\n<p class=\"wp-block-paragraph\">Additionally, my tenure at 2K Sports was marked by close collaboration with technical artists and graphics programmers. Together, we pushed the limitations of the hardware, striving to create the most stunning and lifelike reproductions in our digital games. This partnership was crucial in leveraging the available technology to its fullest potential, ensuring that our titles not only looked spectacular but also remained at the cutting edge of graphical innovation in sports gaming.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Throughout my time at 2K Sports, my roles and responsibilities all converged towards a singular goal: to deliver a sports gaming experience that was not only technically impressive but also emotionally captivating, fulfilling the expectations of a simulation that felt as real and exhilarating as the actual sports themselves.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/2_Reds_Facade.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"720\" height=\"405\" src=\"/assets/images/2015/08/2_Reds_Facade.jpg\" alt=\"2_Reds_Facade\" class=\"wp-image-293\"></a><figcaption class=\"wp-element-caption\">Great American Ballpark - Home of the Cincinnati Reds</figcaption></figure>\n</div>\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/ClassicPoloGrounds_Stadium1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1280\" height=\"720\" src=\"/assets/images/2015/08/ClassicPoloGrounds_Stadium1.jpg\" alt=\"ClassicPoloGrounds_Stadium1\" class=\"wp-image-292\"></a><figcaption class=\"wp-element-caption\">Polo Grounds - Old home of the New York Giants - before they moved to SF</figcaption></figure>\n</div>\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"MLB 2K Sports video\" width=\"760\" height=\"428\" src=\"https://www.youtube.com/embed/vCYMSLbMqOQ\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\"></iframe>\n</div></figure>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_tigers_stadium.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1911\" height=\"1065\" src=\"/assets/images/2013/01/2k_tigers_stadium.jpg\" alt=\"2k_tigers_stadium\" class=\"wp-image-183\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_twins_stadium.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1911\" height=\"1065\" src=\"/assets/images/2013/01/2k_twins_stadium.jpg\" alt=\"2k_twins_stadium\" class=\"wp-image-184\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_yankee_stadium.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1920\" height=\"1065\" src=\"/assets/images/2013/01/2k_yankee_stadium.jpg\" alt=\"2k_yankee_stadium\" class=\"wp-image-185\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_giants_stadium.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1911\" height=\"1065\" src=\"/assets/images/2013/01/2k_giants_stadium.jpg\" alt=\"2k_giants_stadium\" class=\"wp-image-186\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_giants_stadium_02.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1911\" height=\"1065\" src=\"/assets/images/2013/01/2k_giants_stadium_02.jpg\" alt=\"2k_giants_stadium_02\" class=\"wp-image-187\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/2k_rays_stadium.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1911\" height=\"1065\" src=\"/assets/images/2013/01/2k_rays_stadium.jpg\" alt=\"2k_rays_stadium\" class=\"wp-image-188\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2013/01/cropped-header_samiam3d21.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1600\" height=\"230\" src=\"/assets/images/2013/01/cropped-header_samiam3d21.jpg\" alt=\"cropped-header_samiam3d21.jpg\" class=\"wp-image-266\"></a></figure>\n</div>\n\n\n\n\n\n\n<h1 class=\"wp-block-heading\" id=\"other-projects\"><strong>Other projects</strong></h1>\n\n\n\n<p class=\"wp-block-paragraph\">Toy Truck Prototype - Canceled&nbsp;side-scrolling mobile game. Developed art style,&nbsp;created all environments&nbsp;and vehicles.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/jungle_01_colorCorrections.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"2200\" height=\"1184\" src=\"/assets/images/2015/08/jungle_01_colorCorrections.jpg\" alt=\"jungle_01_colorCorrections\" class=\"wp-image-297\"></a></figure>\n</div>\n\n\n\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter\"><a href=\"/assets/images/2015/08/Work_in_progress.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1600\" height=\"861\" src=\"/assets/images/2015/08/Work_in_progress.jpg\" alt=\"Work_in_progress\" class=\"wp-image-296\"></a></figure>\n</div>";
